SELECT id, user_id, session_id, content, agent_name, intent_tag, turn_count, created_at, updated_at,
       1 - (embedding <=> #{embedding,typeHandler=com.example.smartassistant.consumer.handler.FloatArrayTypeHandler}::vector) AS similarity
FROM user_conversation_docs
WHERE user_id = #{userId}
ORDER BY embedding <=> #{embedding,typeHandler=com.example.smartassistant.consumer.handler.FloatArrayTypeHandler}::vector
LIMIT #{topK}

SELECT * FROM user_conversation_docs
WHERE user_id = #{userId}
ORDER BY created_at DESC
